# Weekly utilization tracker with alert logic

class CommitmentUtilizationTracker:
    def __init__(self, monthly_committed_tokens: int, alert_threshold_pct: float = 65.0):
        self.monthly_committed = monthly_committed_tokens
        self.alert_threshold = alert_threshold_pct
        self.weekly_usage = []

    def record_weekly_usage(self, tokens_consumed: int) -> dict:
        monthly_projected = tokens_consumed * 4.33
        utilization_pct = (monthly_projected / self.monthly_committed) * 100
        record = {
            'week': len(self.weekly_usage) + 1,
            'tokens': tokens_consumed,
            'projected_monthly': int(monthly_projected),
            'utilization_pct': round(utilization_pct, 1),
            'alert': utilization_pct < self.alert_threshold
        }
        self.weekly_usage.append(record)
        return record

    def consecutive_under_alert_weeks(self) -> int:
        count = 0
        for r in reversed(self.weekly_usage):
            if r['alert']:
                count += 1
            else:
                break
        return count

tracker = CommitmentUtilizationTracker(monthly_committed_tokens=10_000_000)
for weekly_tokens in [7_200_000, 6_800_000, 5_900_000, 6_100_000]:
    r = tracker.record_weekly_usage(weekly_tokens)
    print(f"Week {r['week']}: {r['utilization_pct']}% utilization {'[ALERT]' if r['alert'] else '[OK]'}")

if tracker.consecutive_under_alert_weeks() >= 2:
    print('ACTION: Escalate to FinOps for commitment review')
